import { readFile, writeFile } from "node:fs/promises";
import { basename, dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const rootDir = resolve(dirname(fileURLToPath(import.meta.url)), "..");

const templates = [
  ["ANDROID_TEMPLATE_BODY", "templates/android.yaml"],
  ["NAS_TEMPLATE_BODY", "templates/nas-debian.yaml"],
  ["WINDOWS_TEMPLATE_BODY", "templates/windows.yaml"],
];

const outputPath = resolve(rootDir, "src/core/default-template-bodies.js");
const checkOnly = process.argv.includes("--check");

const lines = [
  "// This file is generated by scripts/generate-template-bodies.mjs.",
  "// Edit templates/*.yaml instead.",
  "",
];

for (const [exportName, relativePath] of templates) {
  const body = await expandIncludes(await readTemplate(relativePath));
  lines.push(`export const ${exportName} = ${templateLiteral(body)};`, "");
}

const output = `${lines.join("\n")}`;

if (checkOnly) {
  let current = "";
  try {
    current = await readFile(outputPath, "utf8");
  } catch (error) {
    if (error.code !== "ENOENT") throw error;
  }

  if (current !== output) {
    console.error(`${basename(outputPath)} is out of sync. Run npm run templates:generate.`);
    process.exit(1);
  }
} else {
  await writeFile(outputPath, output);
}

async function readTemplate(relativePath) {
  const body = await readFile(resolve(rootDir, relativePath), "utf8");
  return body.endsWith("\n") ? body.slice(0, -1) : body;
}

function templateLiteral(value) {
  return `\`${value.replaceAll("\\", "\\\\").replaceAll("`", "\\`").replaceAll("${", "\\${")}\``;
}

async function expandIncludes(body) {
  const output = [];
  for (const line of body.split("\n")) {
    const match = line.match(/^(\s*)#\s*t-sub:include\s+(.+?)\s*$/);
    if (!match) {
      output.push(line);
      continue;
    }

    const [, indent, relativePath] = match;
    const entries = await readRuleEntries(relativePath);
    output.push(...entries.map((entry) => `${indent}- ${entry}`));
  }
  return output.join("\n");
}

async function readRuleEntries(relativePath) {
  const body = await readFile(resolve(rootDir, relativePath), "utf8");
  return body
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line && !line.startsWith("#"));
}
